export type RadicalComponent =
  | { type: 'text'; char: string }
  | { type: 'symbol'; id: GlyphCropId }

export type RadicalSegment = {
  components: RadicalComponent[]
  kind: RadicalKind
}

export type RadicalKeyData = {
  key: string
  corner?: RadicalSegment
  lines: RadicalSegment[][]
}

